#include <iostream>
#include <string>
#include <vector>
#include <utility>

// Assume getReversedString is provided by the user's code
std::string getReversedString(std::string input_word);

int main() {
    std::vector<std::pair<std::string, std::string>> tests = {
        {"hello", "olleh"},
        {"world", "dlrow"},
        {"a", "a"},
        {"(empty_input)", ""} // (empty_input) simulates EOF for std::cin >> word
    };

    for (const auto& test : tests) {
        std::string input_for_func = test.first;
        if (input_for_func == "(empty_input)") {
            input_for_func = ""; // When std::cin fails, word becomes empty.
        }

        std::string expected_output = test.second;
        std::string actual_output = getReversedString(input_for_func);

        if (actual_output == expected_output) {
            std::cout << "Test passed for input \"" << test.first << "\"" << std::endl;
        } else {
            std::cout << "Test FAILED for input \"" << test.first << "\". Expected: \""
                      << expected_output << "\", Got: \"" << actual_output << "\"" << std::endl;
        }
    }
    return 0;
}
